{
  "artefact_id": "billing-parametrize",
  "owner": "ruslan@faion.net",
  "parametrizations": [
    {
      "test_function": "test_create_invoice_validation",
      "argnames": "field, value, expected_error",
      "cases": [
        {"id": "amount-negative",  "args": ["amount", "-5", "must be positive"]},
        {"id": "amount-non-numeric","args": ["amount", "abc", "must be a number"]},
        {"id": "due-date-past",    "args": ["due_date", "2020-01-01", "must be in the future"]},
        {"id": "missing-customer", "args": ["customer_uid", null, "this field is required"]}
      ],
      "ids_descriptive": true,
      "uses_indirect": false
    },
    {
      "test_function": "test_invoice_detail_by_role",
      "argnames": "client_fixture, expected_status",
      "cases": [
        {"id": "anonymous-401",      "args": ["api_client", 401]},
        {"id": "user-owns-200",      "args": ["authenticated_client", 200]},
        {"id": "user-cross-403",     "args": ["other_authenticated_client", 403]},
        {"id": "admin-200",          "args": ["admin_client", 200]}
      ],
      "ids_descriptive": true,
      "uses_indirect": false
    }
  ],
  "version": "1.0.0",
  "last_reviewed": "2026-05-22"
}
